using System;
using UnityEditor;
using UnityEngine;
namespace TheVayuputra
{
    [InitializeOnLoad]
    public class PackageRatePopup : EditorWindow
    {
        //=========================================================
        // CONFIG
        //=========================================================

        private const string PACKAGE_NAME = "Toon Shader Pack";

        // Add "#reviews" to open the reviews section directly.
        private const string RATE_URL = "https://assetstore.unity.com/packages/vfx/shaders/toon-shader-pack-10-stylized-materials-urp-mobile-optimized-378150#reviews";

        // Recommended banner size:
        // 480 x 280 px (3:2 aspect ratio)
        // PNG format works best.
        // https://tinypng.com/
        // https://base64.guru/converter/encode/image
        private const string BANNER_BASE64 = "";

        //=========================================================

        private static Texture2D s_BannerTexture;

        private static string NeverShowKey =>
            $"{Application.productName}_{PACKAGE_NAME}_RatePopup_Disabled";

        private static string SessionKey =>
        $"{Application.productName}_{PACKAGE_NAME}_RatePopup_ShownThisSession";

        static PackageRatePopup()
        {
            EditorApplication.delayCall += ShowPopupOnStartup;
        }

        private static void ShowPopupOnStartup()
        {
            if (EditorPrefs.GetBool(NeverShowKey, false))
                return;

            // Already shown during this Unity session?
            if (SessionState.GetBool(SessionKey, false))
                return;

            SessionState.SetBool(SessionKey, true);

            OpenWindow();
        }

        [MenuItem("The Vayuputra/Support " + PACKAGE_NAME)]
        private static void OpenWindow()
        {
            var window = GetWindow<PackageRatePopup>(
                true,
                $"Rate {PACKAGE_NAME}",
                true);

            window.minSize = new Vector2(500, 500);
            window.maxSize = window.minSize;
        }

        private static Texture2D BannerTexture
        {
            get
            {
                if (s_BannerTexture != null)
                    return s_BannerTexture;

                if (string.IsNullOrEmpty(BANNER_BASE64))
                    return null;

                byte[] bytes = Convert.FromBase64String(BANNER_BASE64);

                s_BannerTexture = new Texture2D(2, 2);
                s_BannerTexture.LoadImage(bytes);

                return s_BannerTexture;
            }
        }

        private void OnGUI()
        {
            GUILayout.Space(10);

            DrawBanner();

            GUILayout.Space(15);

            GUIStyle titleStyle = new GUIStyle(EditorStyles.boldLabel)
            {
                alignment = TextAnchor.MiddleCenter,
                fontSize = 17
            };

            GUILayout.Label(
                $"⭐ Enjoying {PACKAGE_NAME}?",
                titleStyle);

            GUILayout.Space(8);

            GUIStyle bodyStyle = new GUIStyle(EditorStyles.wordWrappedLabel)
            {
                alignment = TextAnchor.MiddleCenter
            };

            GUILayout.Label(
                "Your review helps support future updates and improvements.\nThank you for using this package ❤️",
                bodyStyle);

            GUILayout.FlexibleSpace();

            DrawRateButton();

            GUILayout.Space(8);

            if (GUILayout.Button("Maybe Later", GUILayout.Height(32)))
            {
                Close();
            }

            GUILayout.Space(15);

            DrawNeverShowAgain();

            GUILayout.Space(10);
        }

        private void DrawBanner()
        {
            if (BannerTexture == null)
                return;

            Rect rect = GUILayoutUtility.GetRect(
                480,
                280,
                GUILayout.ExpandWidth(true));

            GUI.DrawTexture(
                rect,
                BannerTexture,
                ScaleMode.ScaleToFit);
        }

        private void DrawRateButton()
        {
            GUIStyle rateButtonStyle = new GUIStyle(GUI.skin.button)
            {
                fontSize = 16,
                fontStyle = FontStyle.Bold,
                alignment = TextAnchor.MiddleCenter
            };

            if (GUILayout.Button(
                    "⭐ Rate Us",
                    rateButtonStyle,
                    GUILayout.Height(50)))
            {
                Application.OpenURL(RATE_URL);
                Close();
            }
        }

        private void DrawNeverShowAgain()
        {
            GUIStyle style = new GUIStyle(EditorStyles.miniLabel)
            {
                alignment = TextAnchor.MiddleCenter
            };

            Rect rect = GUILayoutUtility.GetRect(
                new GUIContent("Never show this again"),
                style);

            EditorGUIUtility.AddCursorRect(
                rect,
                MouseCursor.Link);

            if (GUI.Button(
                    rect,
                    "Never show this again",
                    style))
            {
                EditorPrefs.SetBool(
                    NeverShowKey,
                    true);

                Close();
            }
        }
    }

}